BEGIN TRANSACTION;
CREATE TABLE `user` (`id` integer PRIMARY KEY AUTOINCREMENT,`username` text NOT NULL,`password` text NOT NULL,`email` text NOT NULL,`role` text NOT NULL DEFAULT "user",`is_verified` numeric DEFAULT false,`is_active` numeric DEFAULT true,`avatar` text,`bio` text,`last_login_at` datetime,`login_attempts` integer DEFAULT 0,`locked_until` datetime,`email_verified_at` datetime,`created_at` datetime,`updated_at` datetime,`deleted_at` datetime,`is_admin` numeric DEFAULT false,CONSTRAINT `uni_user_username` UNIQUE (`username`),CONSTRAINT `uni_user_email` UNIQUE (`email`));
INSERT INTO user VALUES(1,'admin','$2a$14$PJo/vr8yryew26AmiEBM9OVm6zRIVJ5hyITiYMQc8ipuqaqbPdYXK','admin@example.com','ADMIN',1,1,'','','2025-12-17 19:19:20.669347687+00:00',0,NULL,NULL,'2025-12-17 18:32:41.909127378+00:00','2025-12-17 19:19:20.669534587+00:00',NULL,1);
CREATE TABLE `blog_post` (`id` integer PRIMARY KEY AUTOINCREMENT,`title` text NOT NULL,`slug` text NOT NULL,`excerpt` text,`content` longtext NOT NULL,`tags` text,`categories` text,`cover_image_url` text,`access_level` varchar(20) NOT NULL DEFAULT "PUBLIC",`status` varchar(20) NOT NULL DEFAULT "DRAFT",`published_at` datetime,`last_edited_at` datetime,`author_id` integer NOT NULL,`created_at` datetime,`updated_at` datetime,`deleted_at` datetime,CONSTRAINT `fk_blog_post_author` FOREIGN KEY (`author_id`) REFERENCES `user`(`id`),CONSTRAINT `uni_blog_post_slug` UNIQUE (`slug`));
INSERT INTO blog_post VALUES(1,'React 备忘清单','react-bei-wang-qing-dan','',replace('React 备忘清单\n===\n\n[![NPM version](https://img.shields.io/npm/v/react.svg?style=flat)](https://npmjs.org/package/react)\n[![Downloads](https://img.shields.io/npm/dm/react.svg?style=flat)](https://www.npmjs.com/package/react)\n[![Repo Dependents](https://badgen.net/github/dependents-repo/facebook/react)](https://github.com/facebook/react/network/dependents)\n[![Github repo](https://badgen.net/badge/icon/Github?icon=github&label)](https://github.com/facebook/react)\n\n适合初学者的综合 React 备忘清单\n<!--rehype:style=padding-top: 12px;-->\n\n入门\n----\n\n### 介绍\n\nReact 是一个用于构建用户界面的 JavaScript 库\n\n- [React 官方文档](https://react.dev) _(react.dev)_\n- [Styled Components 备忘清单](./styled-components.md) _(jaywcjlove.github.io)_\n- [TypeScript JSX 备忘清单](./typescript.md#jsx) _(jaywcjlove.github.io)_\n\n```js\nimport {createRoot} from ''react-dom/client''\nimport App from ''./App''\n```\n\n-----\n\n```jsx\nconst elm = document.getElementById(''app'')\nconst root = createRoot(elm);\nroot.render(<App />);\n```\n\n#### 快速创建 **React** 项目 ([CRA](https://github.com/facebook/create-react-app))\n\n```shell\nnpx create-react-app my-app\n```\n\n### 导入多个导出\n\n```jsx\nimport React, {Component} from ''react''\nimport ReactDOM from ''react-dom''\n```\n\n-----\n\n```jsx\nexport class Hello extends Component {\n  ...\n}\nexport default function World() {\n  /* ... */\n}\n```\n\n使用 `export` 导出 **`Hello`**，`export default` 导出 **`World`** 组件\n\n```jsx\nimport World, { Hello } from ''./hello.js'';\n```\n\n使用 `import` 导入 `Hello` 组件，在示例中使用。\n\n### React 组件中的 CSS\n\n```jsx {2,5}\nimport React from "react";\nimport "./Student.css";\n\nexport const Student = (\n  <div className="Student"></div>\n);\n```\n\n注意：类属性 `className`\n\n```jsx\nconst divStyle = {\n  backgroundImage: ''url('' + imgUrl + '')'',\n};\nexport const Student = (\n  <div style={divStyle}></div>\n);\n```\n\n### 属性\n\n```jsx\n<Student name="Julie" age={23}\n  pro={true} />\n```\n\n函数组件 `Student` 中访问属性\n\n```jsx\nfunction Student(props) {\n  return <h1>Hello, {props.name}</h1>;\n}\n```\n\nClass 组件 `Student` 中访问属性\n\n```jsx\nclass Student extends React.Component {\n  render() {\n    return (\n      <h1>Hello, {this.props.name}</h1>\n    );\n  }\n}\n```\n\n`class` 组件使用 `this.props` 访问传递给组件的属性。\n\n### Children\n<!--rehype:wrap-class=row-span-2-->\n\n```jsx\nfunction Example() {\n  return (\n    <AlertBox>\n      <h1>您有待处理的通知</h1>\n    </AlertBox>\n  )\n}\n```\n\n函数 `AlertBox` 组件\n\n```jsx {4}\nfunction AlertBox(props) {\n  return (\n    <div className="alert-box">\n      {props.children}\n    </div>\n  );\n}\n```\n\n-----\n\n```jsx\n{props.children}\n```\n\nClass `AlertBox` 组件，与函数组件 `AlertBox` 组件相同\n\n```jsx {5}\nclass AlertBox extends React.Component {\n  render () {\n    return (\n      <div className="alert-box">\n        {this.props.children}\n      </div>\n    );\n  }\n}\n```\n\n-----\n\n```jsx\n{this.props.children}\n```\n\n`children` 作为子组件的的属性传递。\n\n### State\n<!--rehype:wrap-class=row-span-3-->\n\n函数中的 State，Hook 是 React 16.8 的新增特性\n\n```jsx {4,8}\nimport { useState } from ''react'';\n\nfunction Student() {\n  const [count, setCount] = useState(0);\n  const click = () => setCount(count + 1);\n  return (\n    <div>\n      <p>您点击了 {count} 次</p>\n      <button onClick={click}>\n        点击我\n      </button>\n    </div>\n  );\n}\n```\n\n使用 `setState` 更新状态，下面是函数组件读取状态\n\n```jsx\n<p>您点击了 {count} 次</p>\n```\n\n#### Class 中的 State\n\n```jsx {6,12,20}\nimport React from ''react'';\n\nclass Student extends React.Component {\n  constructor(props) {\n    super(props);\n    this.state = {count: 1};\n    // 确保函数可以访问组件属性（ES2015）\n    this.click = this.click.bind(this);\n  }\n  click() {\n    const count = this.state.count;\n    this.setState({ count: count + 1})\n  }\n  render() {\n    return (\n      <div>\n        <button onClick={this.click}>\n          点击我\n        </button>\n        <p>您点击了{this.state.count}次</p>\n      </div>\n    );\n  }\n}\n```\n\n使用 `setState` 更新状态，`class` 组件中不能使用 <yel>~~hooks~~</yel>。下面是 `class` 组件读取状态\n\n```jsx\n<p>您点击了{this.state.count}次</p>\n```\n\n### 循环\n\n```jsx\nconst elm = [''one'', ''two'', ''three''];\nfunction Student() {\n  return (\n    <ul>\n      {elm.map((value, index) => (\n        <li key={index}>{value}</li>\n      ))}\n    </ul>\n  );\n}\n```\n\n`key` 值在兄弟节点之间必须唯一\n\n### 事件监听\n\n```jsx\nexport default function Hello() {\n  function handleClick(event) {\n    event.preventDefault();\n    alert("Hello World");\n  }\n\n  return (\n    <a href="/" onClick={handleClick}>\n      Say Hi\n    </a>\n  );\n}\n```\n\n### 函数注入\n\n```jsx\nfunction addNumbers(x1, x2) {\n  return x1 + x2;\n}\n\nconst element = (\n  <div>\n    {addNumbers(2, 5)}\n  </div>\n);\n```\n\n### 嵌套\n\n```jsx\nimport { useState } from ''react''\nimport Avatar from ''./Avatar'';\nimport Profile from ''./Profile'';\n\nfunction Student() {\n  const [count, setCount] = useState(0);\n  return (\n    <div>\n      <Avatar src={count} />\n      <Profile username={count} />\n    </div>\n  );\n}\n```\n\n### Portals\n\nReact 并_没有_创建一个新的 `div`。它只是把子元素渲染到 `domNode` 中。`domNode` 是一个可以在任何位置的有效 DOM 节点。\n\n```jsx\nrender() {\n  return ReactDOM.createPortal(\n    this.props.children,\n    domNode\n  );\n}\n```\n\n提供了一种将子节点渲染到存在于父组件以外的 DOM 节点的优秀的方案\n\n### Fragment\n<!--rehype:wrap-class=row-span-2-->\n\n```jsx {1,6,9}\nimport { Fragment } from ''react''\nimport Avatar from ''./Avatar'';\nimport Profile from ''./Profile'';\n\nconst Student = () => (\n  <Fragment>\n    <Avatar src="./demo.jpg" />\n    <Profile username="name" />\n  </Fragment>\n);\n```\n\n从 `v16.2.0` 开始 `Fragment` 可用于返回多个子节点，而无需向 DOM 添加额外的包装节点。或者使用 `<></>` 效果是一样的。\n\n```jsx {2,5}\nconst Student = () => (\n  <>\n    <Avatar src="./demo.jpg" />\n    <Profile username="name" />\n  </>\n);\n```\n\n查看: [Fragments & strings](https://reactjs.org/blog/2017/09/26/react-v16.0.html#new-render-return-types-fragments-and-strings)\n\n### 返回字符串\n\n```jsx {2}\nrender() {\n  return ''Look ma, no spans!'';\n}\n```\n\n您可以只返回一个字符串。查看: [Fragments & strings](https://reactjs.org/blog/2017/09/26/react-v16.0.html#new-render-return-types-fragments-and-strings)\n\n### 返回数组\n\n```jsx\nconst Student = () => [\n  <li key="A">First item</li>,\n  <li key="B">Second item</li>\n];\n```\n\n不要忘记 `key`！查看: [Fragments & strings](https://reactjs.org/blog/2017/09/26/react-v16.0.html#new-render-return-types-fragments-and-strings)\n\n### Refs 转发\n\n```jsx\nconst FancyButton = React.forwardRef(\n  (props, ref) => (\n    <button ref={ref} className="btn">\n      {props.children}\n    </button>\n  )\n);\n```\n\n#### 使用\n\n```jsx\n// 你可以直接获取 DOM button 的 ref：\nconst ref = React.createRef();\n\n<FancyButton ref={ref}>\n  点击我\n</FancyButton>;\n```\n\n### Class 组件内部使用 ref 属性\n\n```jsx {6,10}\nimport {Component,createRef} from ''react''\n\nclass MyComponent extends Component {\n  constructor(props) {\n    super(props);\n    this.myRef = createRef();\n  }\n\n  render() {\n    return <div ref={this.myRef} />;\n  }\n}\n```\n\n提示：Refs 适用于类组件，但不适用于函数组件（除非您使用 useRef hook，请参阅[hooks](#hooks)）\n\n### 函数组件内部使用 ref 属性\n\n```jsx {3,9}\nfunction CustomTextInput(props) {\n  // 这里必须声明 $input，这样 ref 才可以引用它\n  const $input = useRef(null);\n  function handleClick() {\n    $input.current.focus();\n  }\n  return (\n    <div>\n      <input type="text" ref={$input} />\n      <input\n        type="button" value="聚焦文本输入"\n        onClick={handleClick}\n      />\n    </div>\n  );\n}\n```\n\n### 严格模式 StrictMode\n\n```jsx {3,8}\n<div>\n  <Header />\n  <React.StrictMode>\n    <div>\n      <ComponentOne />\n      <ComponentTwo />\n    </div>\n  </React.StrictMode>\n  <Footer />\n</div>\n```\n\n-----\n\n- [识别不安全的生命周期](https://zh-hans.reactjs.org/docs/strict-mode.html#identifying-unsafe-lifecycles)\n- [关于使用过时字符串 ref API 的警告](https://zh-hans.reactjs.org/docs/strict-mode.html#warning-about-legacy-string-ref-api-usage)\n- [关于使用废弃的 findDOMNode 方法的警告](https://zh-hans.reactjs.org/docs/strict-mode.html#warning-about-deprecated-finddomnode-usage)\n- [检测意外的副作用](https://zh-hans.reactjs.org/docs/strict-mode.html#detecting-unexpected-side-effects)\n- [检测过时的 context API](https://zh-hans.reactjs.org/docs/strict-mode.html#detecting-legacy-context-api)\n- [确保可复用的状态](https://zh-hans.reactjs.org/docs/strict-mode.html#ensuring-reusable-state)\n\n突出显示应用程序中潜在问题的工具。请参阅：[严格模式](https://zh-hans.reactjs.org/docs/strict-mode.html)\n\n### Profiler\n<!--rehype:wrap-class=col-span-2-->\n\n测量一个 React 应用多久渲染一次以及渲染一次的 `代价`\n\n```jsx\n<Profiler id="Navigation" onRender={callback}>\n  <Navigation {...props} />\n</Profiler>\n```\n\n为了分析 `Navigation` 组件和它的子代。应该在需要时才去使用它。\n\n:- | :-\n:- | :-\n`id(string)` | 发生提交的 `Profiler` 树的 `id`\n`onRender(function)` | 组件树任何组件 “提交” 一个更新的时候调用这个函数\n\n#### onRender 回调函数\n\n:- | :-\n:- | :-\n`phase: "mount" \| "update"` |  判断是由 `props`/`state`/`hooks` 改变 或 “第一次装载” 引起的重渲染\n`actualDuration: number` | 本次更新在渲染 Profiler 和它的子代上花费的时间\n`baseDuration: number` | 在 Profiler 树中最近一次每一个组件 render 的持续时间\n`startTime: number` | 本次更新中 React 开始渲染的时间戳\n`commitTime: number` | 本次更新中 React commit 阶段结束的时间戳\n`interactions: Set` | 当更新被制定时，“[interactions](https://fb.me/react-interaction-tracing)” 的集合会被追踪\n\n默认值\n---\n\n### Class 组件默认 props\n<!--rehype:wrap-class=row-span-2-->\n\n```jsx\nclass CustomButton extends React.Component {\n  // ...\n}\nCustomButton.defaultProps = {\n  color: ''blue''\n};\n```\n\n#### 使用\n\n```jsx\n<CustomButton /> ;\n```\n\n不传值 `props.color` 将自动设置为 `blue`\n\n### Class 组件默认 state\n<!--rehype:wrap-class=row-span-2-->\n\n```jsx\nclass Hello extends Component {\n  constructor (props) {\n    super(props)\n    this.state = { visible: true }\n  }\n}\n```\n\n在构造 `constructor()`中设置默认状态。\n\n```jsx\nclass Hello extends Component {\n  state = { visible: true }\n}\n```\n\n### 函数组件默认 props\n\n```jsx\nfunction CustomButton(props) {\n  const { color = ''blue'' } = props;\n  return <div>{color}</div>\n}\n```\n\n### 函数组件默认 state\n\n```jsx\nfunction CustomButton() {\n  const [color, setColor]=useState(''blue'')\n  return <div>{color}</div>\n}\n```\n\nProps\n---\n\n### Props 的 Spread 运算符\n\n扩展运算符可用于一次传递所有 Props。\n\n```jsx\nfunction Profile(props) {\n  return <p>{props.name}, {props.age}</p>;\n}\n\nconst user = { name: "John", age: 25 };\n<Profile {...user}/>\n```\n\n### 什么是 Props？\n\n- Props（“properties”的缩写）用于将数据从父组件传递到子组件。\n- 它们是只读的，不能在子组件内修改。\n\n```jsx\n<MyComponent propName="value" />\n```\n\n### 将 Pros 传递给组件\n\n您可以通过 JSX 中的属性将 props 从父组件传递到子组件。\n\n```jsx\nfunction ParentComponent() {\n  return <ChildComponent name="John" age={25} />;\n}\n\nfunction ChildComponent (props) {\n  return <div>Hello，{props.name}. You are {props.age} years old. </div>;\n}\n```\n\n### 解构 props\n\nprops 可以解构以便于访问。\n\n```jsx\nfunction Greeting({ name }) {\n  return <h1>Hello, {name}!</h1>;\n}\n```\n\n### 访问功能组件中的 Props\n\n可以使用 props 对象在功能组件中访问 Props。\n\n```jsx\nfunction Greeting(props) {\n  return <h1>Hello, {props.name}!</h1>;\n}\n```\n\n### 使用 Pros 进行条件渲染\n\n道具可用于组件内部的条件渲染。\n\n```jsx\nfunction Greeting({ name, isLoggedIn }) {\n  return isLoggedIn ? <hl>Welcome back, {name}</h1>: <h1>Please log in</h1>;\n}\n```\n\n### Prop Drilling（属性传递）\n<!--rehype:wrap-class=row-span-2-->\n\n```js\nfunction Parent() {\n  const name = "John";\n  return <Child name={name}/>;\n}\n\nfunction Child({ name }) {\n  return <Grandchild name={name} />\n}\n\nfunction Grandchild({ name }) {\n  return <p>{name}</p>;\n}\n```\n\n将属性（props）在多个组件层级中逐层传递可能会变得繁琐。这种方式称为属性传递（prop drilling）。\n\n### Props 与 State\n<!--rehype:wrap-class=row-span-2-->\n\n- `props` 被传递给组件并且是不可变的。\n- `State` 是组件的本地状态，可以更改。\n\n```jsx\nfunction ChildComponent({ name }) {\n  return <h2>Hi,my name is {name}.</h2>;\n}\n\nfunction ParentComponent() {\n  // State to manage the name value\n  const ［name, setName］= usestate(''John'');\n  const changeName = () => {\n    setName(''Jane'');\n  };\n  return (\n    <div>\n      <ChildComponent name={name}/>\n      <button onClick={changeName}>\n        Change Names\n      </button>\n    </div>\n  );\n}\n```\n\n### 默认 props\n\n```jsx\nfunction Greeting({ name = "Bob" } = 0}) {\n  return <h1>Hello, {name}!</h1>;\n}\n// Renders "Hello, Bob!"\n< Greeting />\n```\n\n您可以为 `props` 设置默认值。\n\n### 使用 prop 处理事件\n\n你可以将事件处理程序作为 props 传递给 handle 用户交互。\n\n```jsx\nfunction Button({ onClick }) {\n  return < button onClick={onClick}>Click me</button>;\n}\n\nfunction App() {\n  const handleClick = () => alert("Button clicked!"):\n  return <Button onClick={handleClick} />;\n}\n```\n\nJSX\n---\n\n### 介绍\n<!--rehype:wrap-class=row-span-2-->\n\n`JSX` 仅仅只是 `React.createElement(component, props, ...children)` 函数的语法糖\n\n```jsx\n<MyButton color="blue" shadowSize={2}>\n  点击我\n</MyButton>\n```\n\n会编译为\n\n```js\nReact.createElement(\n  MyButton,\n  {color: ''blue'', shadowSize: 2},\n  ''点击我''\n);\n```\n\n没有子节点\n\n```jsx\n<div className="sidebar" />\n```\n\n会编译为\n\n```js\nReact.createElement(\n  ''div'',\n  {className: ''sidebar''}\n)\n```\n\n### JSX 点语法\n\n```jsx\nconst Menu = ({ children }) => (\n  <div className="menu">{children}<div>\n);\n\nMenu.Item = ({ children }) => (\n  <div>{children}<div>\n);\n\n<Menu>\n  <Menu.Item>菜单一</Menu.Item>\n  <Menu.Item>菜单二</Menu.Item>\n<Menu>\n```\n\n### JSX Element\n\n```jsx\nlet element = <h1>Hello, world!</h1>;\nlet emptyHeading = <h1 />;\n\nconst root = ReactDOM.createRoot(\n  document.getElementById(''root'')\n);\n\nconst element = <h1>Hello, world</h1>;\nroot.render(element);\n```\n\n参考：[渲染元素](https://reactjs.org/docs/rendering-elements.html)\n\n### JSX 属性\n\n```jsx\nconst avatarUrl = "img/picture.jpg"\nconst element = <img src={avatarUrl} />;\n\nconst element = (\n  <button className="btn">\n    点击我\n  </button>\n);\n```\n\n注意：类属性 `className`\n\n### JSX 表达式\n\n```jsx\nlet name = ''张三'';\nlet element = <h1>Hello, {name}</h1>;\n\nfunction fullName(firstName, lastName) {\n  return firstName + '' '' + lastName;\n}\nlet element = (\n  <h1>\n    Hello, {fullName(''三'', ''张'')}\n  </h1>\n);\n```\n\n### JSX style\n\n```jsx\nconst divStyle = {\n  color: ''blue'',\n  backgroundImage: ''url('' + imgUrl + '')'',\n};\nfunction MyComponent() {\n  return <div style={divStyle}>组件</div>;\n}\n```\n\n### JSX dangerouslySetInnerHTML\n\n```jsx\nconst markup = {__html: ''我 &middot; 你'' };\n\nconst MyComponent = () => (\n  <div dangerouslySetInnerHTML={markup} />\n);\n```\n\n`dangerouslySetInnerHTML` 是 React 为浏览器 DOM 提供 `innerHTML` 的替换方案。\n\n### JSX htmlFor\n\n```jsx\nconst MyComponent = () => (\n  <div>\n    <input type="radio" id="ab" name="v">\n    <label for="ab">HTML</label>\n  </div>\n);\n```\n\n`for` 在 `JS` 中是保留字，JSX 元素使用了 `htmlFor` 代替\n\n### JSX defaultValue\n\n非受控组件的属性，设置组件第一次挂载时的 `value`\n\n```jsx\n<textarea defaultValue="Hello" />\n```\n\n`<input>`、`<select>` 和 `<textarea>` 支持 value 属性\n\n### JSX defaultChecked\n\n非受控组件的属性，设置组件是否被选中\n\n```jsx\n<input type="radio" defaultChecked />\n```\n\n类型为 `checkbox` 或 `radio` 时，组件支持 checked 属性\n\n### JSX className\n\n属性用于指定 `CSS` 的 `class`\n\n```jsx\n<div className="warp">...</div>\n```\n\nReact 中使用 [Web Components](https://developer.mozilla.org/zh-CN/docs/Web/Web_Components) 使用 `class` 属性代替\n\n### JSX 条件渲染\n<!--rehype:wrap-class=row-span-2-->\n\n```jsx\nimport React from "react";\n\nfunction formatName(user) {\n  return user.firstName \n    + '' '' \n    + user.lastName;\n}\n\nexport function Greeting(user) {\n  if (user) {\n    return (\n      <h1>你好, {formatName(user)}!</h1>\n    );\n  }\n  return (\n    <h1>你好, 先生。</h1>\n  );\n}\n```\n\n注意：组件必须总是返回一些东西。\n\n#### 使用\n\n```jsx\n<Greeting firstName="三" lastName="张" />\n```\n\n### JSX 三目运算符 / 与运算符 &&\n\n```jsx\nexport default function Weather(props) {\n  const isLoggedIn = props.isLoggedIn;\n  return (\n    <div>\n      <b>{isLoggedIn ? ''已'' : ''未''}</b>登录。\n    </div>\n  );\n}\n```\n\n-----\n\n```js\n{isShow && <div>内容</div>}\n```\n\n### JSX 组件\n\n```jsx\n<Dropdown>\n  下拉列表\n  <Menu>\n    <Menu.Item>菜单一</Menu.Item>\n    <Menu.Item>菜单二</Menu.Item>\n    <Menu.Item>菜单三</Menu.Item>\n  </Menu>\n</Dropdown>\n```\n\n组件名称以大驼峰式命名。\n\n### JSX 元素变量\n\n```jsx\nfunction Greeting(props) {\n  let button;\n  if (props.isLoggedIn) {\n    button = <UserGreeting />;\n  } else {\n    button = <GuestGreeting />;\n  }\n  return <div>{button}</div>;\n}\n```\n\n### JSX 注释\n\n```jsx\nfunction Student() {\n  const [count, setCount] = useState(0);\n  return (\n    <Fragment>\n      {/* 这里写注释 */}\n    </Fragment>\n  );\n}\n```\n\n组件\n----\n\n### 函数组件\n<!--rehype:wrap-class=row-span-2-->\n\n```jsx\nimport React from ''react'';\n\nconst UserName = () => <h1>Kenny</h1>;\n\nexport default function UserProfile() {\n  return (\n    <div className="UserProfile">\n      <div>Hello</div>  \n      <UserName />\n    </div>\n  );\n}\n```\n\n注意：每个组件都需要一个根元素，[更多说明](https://reactjs.org/docs/components-and-props.html)。\n\n### Class 组件\n\n```jsx\nclass Welcome extends React.Component {\n  render() {\n    return <h1>{this.props.name}</h1>;\n  }\n}\n```\n\n### Class 组件 API\n<!--rehype:wrap-class=row-span-2-->\n\n#### 额外的 API\n\n:- | -\n:- | -\n`this.forceUpdate()` | 强制重新渲染\n`this.setState({ ... })` | 更新状态\n`this.setState(state =>{ ... })` | 更新状态\n\n#### 属性\n\n:- | -\n:- | -\n`defaultProps` | 默认 props\n`displayName` | 显示组件名称(用于调试)\n\n#### 实例属性\n\n:- | -\n:- | -\n`this.props` | 组件接受参数\n`this.state` | 组件内状态\n\n### Pure 组件\n\n```jsx\nimport React, {PureComponent} from ''react''\n\nclass MessageBox extends PureComponent {\n  ···\n}\n```\n\n### 高阶组件\n\n```jsx\nimport React, { Component } from ''react'';\n// 高阶组件 with\nconst with = data => WrappedComponent => {\n  return class extends Component {\n    constructor(props) {\n      super(props);\n    }\n    render() {\n      return (\n        <WrappedComponent data={data} />\n      )\n    }\n  }\n}\n```\n\n使用高阶组件\n\n```jsx\nconst LowComponent = (props) => (\n  <div>{props.data}</div>\n);\n\nconst MyComp = with(''Hello'')(LowComponent)\n```\n\n### 包含关系\n\n```jsx\nfunction FancyBorder(props) {\n  return (\n    <div className={''Fancy''+props.color}>\n      {props.children}\n    </div>\n  );\n}\n```\n\n组件可以通过 JSX 嵌套\n\n```jsx\nfunction WelcomeDialog() {\n  return (\n    <FancyBorder color="blue">\n      <h1 className="title">欢迎</h1>\n      <p className="message">\n        感谢您访问我们的宇宙飞船\n      </p>\n    </FancyBorder>\n  );\n}\n```\n\n### 作为参数传递\n\n```jsx\nfunction SplitPane(props) {\n  return (\n    <div className="SplitPane">\n      <div className="left">\n        {props.left}\n      </div>\n      <div className="right">\n        {props.right}\n      </div>\n    </div>\n  );\n}\n\nfunction App() {\n  return (\n    <SplitPane\n      left={<Contacts />}\n      right={<Chat />}\n    />\n  );\n}\n```\n\n给组件 `SplitPane` 传递 `left` 和 `right` 两个组件参数\n\n### 嵌入内部组件\n\n```jsx {2}\nimport React from ''react'';\nimport UserAvatar from "./UserAvatar";\n\nexport default function UserProfile() {\n  return (\n    <div className="UserProfile">\n      <UserAvatar />\n      <UserAvatar />\n    </div>\n  );\n}\n```\n\n注意：假设 `UserAvatar` 在 `UserAvatar.js` 中声明\n\n### 嵌入外部组件\n\n```jsx {2}\nimport React from ''react'';\nimport {Button} from ''uiw'';\nexport default function UserProfile() {\n  return (\n    <div className="UserProfile">\n      <Button type="primary">\n        主要按钮\n      </Button>\n    </div>\n  );\n}\n```\n\n注意：[uiw](http://npmjs.com/uiw) 组件在 [npmjs.com](https://www.npmjs.com) 上找到，需要先安装导入\n\n### 点组件语法技巧\n\n```jsx\nconst Menu = ({ children }) => (\n  <div className="menu">{children}<div>\n);\n\nMenu.Item = ({ children }) => (\n  <div>{children}<div>\n);\n```\n\n-----\n\n```jsx\n<Menu>\n  <Menu.Item>菜单一</Menu.Item>\n  <Menu.Item>菜单二</Menu.Item>\n<Menu>\n```\n\nHooks\n---\n\n### Hooks API 参考\n<!--rehype:wrap-class=row-span-2-->\n\n#### 基础 Hook\n\n方法 | 描述\n:- | -\n`useState` | 返回一个 `state`，更新 `state` 的函数 [#](https://zh-hans.reactjs.org/docs/hooks-reference.html#usestate)\n`useEffect` | 可能有副作用代码的函数 [#](https://zh-hans.reactjs.org/docs/hooks-reference.html#useeffect)\n`useContext` | 接收并返回该 `context` 的当前值 [#](https://zh-hans.reactjs.org/docs/hooks-reference.html#usecontext)\n\n#### 额外的 Hook\n\n方法 | 描述\n:- | -\n`useReducer` | `useState` 的替代方案 [#](https://zh-hans.reactjs.org/docs/hooks-reference.html#usestate)\n`useCallback` | 返回一个回调函数 [#](https://zh-hans.reactjs.org/docs/hooks-reference.html#usecallback)\n`useMemo` | 返回一个 [memoized](https://en.wikipedia.org/wiki/Memoization) 值[#](https://zh-hans.reactjs.org/docs/hooks-reference.html#usememo)\n`useRef` | 返回一个可变的 `ref` 对象 [#](https://zh-hans.reactjs.org/docs/hooks-reference.html#useref)\n`useImperativeHandle` | 暴露给父组件的实例值 [#](https://zh-hans.reactjs.org/docs/hooks-reference.html#useimperativehandle)\n`useLayoutEffect` | DOM 变更后同步调用函数 [#](https://zh-hans.reactjs.org/docs/hooks-reference.html#uselayouteffect)\n`useDebugValue` | 开发者工具中显示标签 [#](https://zh-hans.reactjs.org/docs/hooks-reference.html#usedebugvalue)\n`useDeferredValue` | 接受并返回该值的新副本 [#](https://zh-hans.reactjs.org/docs/hooks-reference.html#usedeferredvalue)\n`useTransition` | 过渡任务的等待状态 [#](https://zh-hans.reactjs.org/docs/hooks-reference.html#usetransition)\n`useId` | 用于生成唯一 ID [#](https://zh-hans.reactjs.org/docs/hooks-reference.html#useid)\n\n#### Library Hooks\n\n方法 | 描述\n:- | -\n`useSyncExternalStore` | 读取和订阅外部数据源 [#](https://zh-hans.reactjs.org/docs/hooks-reference.html#usesyncexternalstore)\n`useInsertionEffect` |  DOM 突变之前 同步触发 [#](https://zh-hans.reactjs.org/docs/hooks-reference.html#usesyncexternalstore)\n\n### 函数式更新\n<!--rehype:wrap-class=col-span-2-->\n\n```jsx\nfunction Counter({ initialCount }) {\n  const [count, setCount] = useState(initialCount);\n  return (\n    <>\n      Count: {count} <button onClick={() => setCount(initialCount)}>Reset</button>\n      <button onClick={() => setCount(prevCount => prevCount - 1)}>-</button>\n      <button onClick={() => setCount(prevCount => prevCount + 1)}>+</button>\n    </>\n  );\n}\n```\n\n### useRef\n\n```jsx\nfunction TextInputWithFocusButton() {\n  const $input = useRef(null);\n  const onButtonClick = () => {\n    $input.current.focus();\n  };\n  return (\n    <>\n      <input ref={$input} type="text" />\n      <button onClick={onButtonClick}>\n        聚焦输入\n      </button>\n    </>\n  );\n}\n```\n\n`current` 指向已挂载到 DOM 上的文本输入元素\n\n### useImperativeHandle\n\n```jsx\nfunction FancyInput(props, ref) {\n  const inputRef = useRef();\n  useImperativeHandle(ref, () => ({\n    focus: () => {\n      inputRef.current.focus();\n    }\n  }));\n  return <input ref={inputRef} />;\n}\nFancyInput = forwardRef(FancyInput);\n```\n\n父组件使用\n\n```jsx\n<FancyInput ref={inputRef} />\ninputRef.current.focus()\n```\n\n### useEffect\n\n```jsx\nuseEffect(() => {\n  const subs = props.source.subscribe();\n  return () => {\n    subs.unsubscribe();\n  };\n}, [props.source]);\n```\n\n### useCallback\n\n```jsx\nconst memoizedCallback = useCallback(\n  () => {\n    doSomething(a, b);\n  },\n  [a, b],\n);\n```\n\n### useMemo\n\n```jsx\nconst memoizedValue = useMemo(\n  () => {\n    return computeExpensiveValue(a, b)\n  },\n  [a, b]\n);\n```\n\n### useId\n\n```jsx\nfunction Checkbox() {\n  const id = useId();\n  return (\n    <>\n      <label htmlFor={id}>\n        你喜欢React吗？\n      </label>\n      <input id={id} type="checkbox" />\n    </>\n  );\n};\n```\n\n用于生成跨服务端和客户端稳定的唯一 `ID` 的同时避免 `hydration` 不匹配\n\n### useDebugValue\n\n```jsx\nfunction useFriendStatus(friendID) {\n  const [\n    isOnline, setIsOnline\n  ] = useState(null);\n  // ...\n  // 在开发者工具中的这个 Hook 旁边显示标签\n  // e.g. "FriendStatus: Online"\n  useDebugValue(\n    isOnline ? ''Online'' : ''Offline''\n  );\n  return isOnline;\n}\n```\n<!--rehype:className=wrap-text -->\n\n不推荐你向每个自定义 `Hook` 添加 `debug` 值\n\n### componentDidMount & componentWillUnmount\n\n```jsx\nuseEffect(\n  () => {\n    // componentDidMount\n    // 组件挂载时，可以在这里完成你的任务\n    return () => {\n      // componentWillUnmount\n      // 卸载时执行，清除 effect\n    };\n  },\n  [ ]\n);\n```\n\n这是一个类似 `class` 组件中 `componentDidMount` & `componentWillUnmount` 两个生命周期函数的写法。\n\n生命周期\n---\n<!--rehype:body-class=cols-2-->\n\n### 挂载\n<!--rehype:wrap-class=row-span-2-->\n\n方法 | 描述\n:- | -\n`constructor` _(props)_  | 渲染前 [#](https://zh-hans.reactjs.org/docs/react-component.html#constructor)\n`static getDerivedStateFromProps()` | 调用 `render` 方法之前调用 [#](https://zh-hans.reactjs.org/docs/react-component.html#static-getderivedstatefromprops)\n`render()`               |  `class` 组件中唯一必须实现的方法 [#](https://reactjs.org/docs/react-component.html#render)\n`componentDidMount()`    | 在组件挂载后(插入 DOM 树中)立即调用 [#](https://reactjs.org/docs/react-component.html#componentdidmount)\n`UNSAFE_componentWillMount()` | 在挂载之前被调用，建议使用 `constructor()` [#](https://zh-hans.reactjs.org/docs/react-component.html#unsafe_componentwillmount)\n\n在 `constructor()` 上设置初始状态。在 `componentDidMount()` 上添加 DOM 事件处理程序、计时器(等），然后在 `componentWillUnmount()` 上删除它们。\n\n### 卸载\n\n方法 | 描述\n:- | -\n`componentWillUnmount()` | 在组件卸载及销毁之前直接调用 [#](https://zh-hans.reactjs.org/docs/react-component.html#componentwillunmount)\n\n### 过时 API\n\n过时方法 | 新方法\n:- | -\n~~`componentWillMount()`~~ | `UNSAFE_componentWillMount()`  [#](https://zh-hans.reactjs.org/docs/react-component.html#unsafe_componentwillmount)\n~~`componentWillReceiveProps()`~~ | `UNSAFE_componentWillReceiveProps()`  [#](https://zh-hans.reactjs.org/docs/react-component.html#unsafe_componentwillreceiveprops)\n~~`componentWillUpdate()`~~ | `UNSAFE_componentWillUpdate()`  [#](https://zh-hans.reactjs.org/docs/react-component.html#unsafe_componentwillupdate)\n\n17+ 之后不再支持，在 `17` 版本之后，只有新的 `UNSAFE_` 生命周期名称可以使用。\n\n### 更新\n<!--rehype:wrap-class=col-span-2-->\n\n方法 | 描述\n:- | -\n`static getDerivedStateFromProps(props, state)` | 调用 `render` 之前调用，在初始挂载及后续更新时都会被调用 [#](https://zh-hans.reactjs.org/docs/react-component.html#static-getderivedstatefromprops)\n`shouldComponentUpdate(nextProps, nextState)` | 如果返回 `false`，则跳过 `render()` [#](https://zh-hans.reactjs.org/docs/react-component.html#static-getderivedstatefromprops)\n`render()` | 在不修改组件 `state` 的情况下，每次调用时都返回相同的结果 [#](https://zh-hans.reactjs.org/docs/react-component.html#render)\n`getSnapshotBeforeUpdate()` | 在发生更改之前从 DOM 中捕获一些信息（例如，滚动位置） [#](https://zh-hans.reactjs.org/docs/react-component.html#getsnapshotbeforeupdate)\n`componentDidUpdate()` | 这里使用 `setState()`，但记得比较 `props`。首次渲染不会执行此方法 [#](https://zh-hans.reactjs.org/docs/react-component.html#componentdidupdate)\n\n### 错误处理\n<!--rehype:wrap-class=col-span-2-->\n\n方法 | 描述\n:- | -\n`static getDerivedStateFromError(error)` | 后代组件抛出错误后被调用，它将抛出的错误作为参数，并返回一个值以更新 `state` [#](https://zh-hans.reactjs.org/docs/react-component.html#static-getderivedstatefromerror)\n`componentDidCatch(error, info)` | 在后代组件抛出错误后被调用，会在“提交”阶段被调用，因此允许执行副作用 [#](https://zh-hans.reactjs.org/docs/react-component.html#componentdidcatch)\n\n### render()\n\n```jsx {2}\nclass Welcome extends React.Component {\n  render() {\n    return <h1>Hello, {this.props.name}</h1>;\n  }\n}\n```\n\n### constructor()\n\n```jsx {1}\nconstructor(props) {\n  super(props);\n  // 不要在这里调用 this.setState()\n  this.state = { counter: 0 };\n  this.handleClick = this.handleClick.bind(this);\n}\n```\n\n### static getDerivedStateFromError()\n<!--rehype:wrap-class=row-span-2-->\n\n```jsx {7,13}\nclass ErrorBoundary extends React.Component {\n  constructor(props) {\n    super(props);\n    this.state = { hasError: false };\n  }\n\n  static getDerivedStateFromError(error) {\n    // 更新 state 使下一次渲染可以显降级 UI\n    return { hasError: true };\n  }\n\n  render() {\n    if (this.state.hasError) {\n      // 你可以渲染任何自定义的降级  UI\n      return <h1>Something went wrong.</h1>;\n    }\n\n    return this.props.children;\n  }\n}\n```\n\n### componentDidUpdate()\n\n```jsx {1}\ncomponentDidUpdate(prevProps) {\n  // 典型用法（不要忘记比较 props）：\n  if (this.props.uid !== prevProps.uid) {\n    this.fetchData(this.props.uid);\n  }\n}\n```\n\n### getSnapshotBeforeUpdate()\n\n```jsx\ngetSnapshotBeforeUpdate(prevProps, prevState) {\n  // 我们是否在 list 中添加新的 items ？\n  // 捕获滚动​​位置以便我们稍后调整滚动位置。\n  if (prevProps.list.length < this.props.list.length) {\n    const list = this.listRef.current;\n    return list.scrollHeight - list.scrollTop;\n  }\n  return null;\n}\n```\n\nPropTypes 属性类型检查\n---\n\n### PropTypes\n<!--rehype:wrap-class=row-span-3-->\n\n```jsx\nimport PropTypes from ''prop-types''\n```\n\n-----\n\n:- | -\n:- | -\n`any` | 任意类型\n`(props, propName, 组件名称)=>{}` | 自定义验证器\n\n#### _基础_\n\n:- | -\n:- | -\n`string` | 字符串\n`number` | 数组\n`func` | 函数\n`bool` | 布尔值\n`symbol` | -\n\n#### _枚举 Enum_\n\n:- | -\n:- | -\n`oneOf(any)` | 枚举类型\n`oneOfType([type])` | 几种类型中的任意一个类型\n\n#### _数组 Array_\n\n:- | -\n:- | -\n`array` | 数组\n`arrayOf` | 数组由某一类型的元素组成\n\n#### _对象 Object_\n\n:- | -\n:- | -\n`object` | 对象\n`objectOf` | 对象由某一类型的值组成\n`instanceOf(...)` | 类的实例\n`shape` | 对象由特定的类型值组成\n`exact` | 有额外属性警告\n\n#### _元素 Elements_\n\n:- | -\n:- | -\n`element` | React 元素\n`elementType` | React 元素类型(即 `MyComponent`)\n`node` | DOM 节点\n\n#### _必需的_\n\n:- | -\n:- | -\n`(···).isRequired` | 必需的\n\n请参阅：[使用 PropTypes 进行类型检查](https://zh-hans.reactjs.org/docs/typechecking-with-proptypes.html)\n\n### 基本类型\n\n```jsx\nMyComponent.propTypes = {\n  email:      PropTypes.string,\n  seats:      PropTypes.number,\n  callback:   PropTypes.func,\n  isClosed:   PropTypes.bool,\n  any:        PropTypes.any\n  symbol:     PropTypes.symbol,\n}\n```\n\n你可以将属性声明为 JS 原生类型，默认都是可选的。\n\n### 必需的\n\n```jsx\nMyComponent.propTypes = {\n  // 确保这个 prop 没有被提供时，会打印警告信息\n  requiredFunc: PropTypes.func.isRequired,\n\n  // 任意类型的必需数据\n  requiredAny: PropTypes.any.isRequired,\n}\n```\n\n你可以在任何 `PropTypes` 属性后面加上 `isRequired`。\n\n### 枚举\n\n```js\nMyComponent.propTypes = {\n  // 只能是特定的值，枚举类型。\n  optionalEnum: PropTypes.oneOf([\n    ''News'', ''Photos''\n  ]),\n  // 一个对象可以是几种类型中的任意一个类型\n  optionalUnion: PropTypes.oneOfType([\n    PropTypes.string,\n    PropTypes.number,\n    PropTypes.instanceOf(Message)\n  ]),\n}\n```\n\n### 元素 Elements\n\n```jsx\nMyComponent.propTypes = {\n  // 任何可被渲染的元素\n  // (包括数字、字符串、元素或数组)\n  // (或 Fragment) 也包含这些类型。\n  node: PropTypes.node,\n\n  // 一个 React 元素。\n  element: PropTypes.element,\n\n  // 一个 React 元素类型（即，MyComponent）\n  elementType: PropTypes.elementType,\n}\n```\n\n### 对象 Object\n\n```jsx\nMyComponent.propTypes = {\n  // 可以指定一个对象由某一类型的值组成\n  objectOf: PropTypes.objectOf(\n    PropTypes.number\n  ),\n  // 可以指定一个对象由特定的类型值组成\n  objectWithShape: PropTypes.shape({\n    color: PropTypes.string,\n    fontSize: PropTypes.number\n  }),\n  // 带有额外属性警告的对象\n  objectWithStrictShape: PropTypes.exact({\n    name: PropTypes.string,\n    quantity: PropTypes.number\n  }),\n}\n```\n\n### 自定义验证器\n\n```jsx\nMyComponent.propTypes = {\n  custom: (props, propName, compName) => {\n    if (!/matchm/.test(props[propName])) {\n      // 它在验证失败时应返回一个 Error 对象\n      return new Error(\n        ''无效的prop `''\n        ` \`${propName}\` 提供给` + \n        ` \`${compName}\`。验证失败。`\n      );\n\n    }\n  },\n}\n```\n\n请不要使用 `console.warn` 或抛出异常，因为这在 `oneOfType` 中不会起作用。\n\n### 自定义的 `arrayOf` 或 `objectOf` 验证器\n<!--rehype:wrap-class=col-span-2 row-span-2-->\n\n```jsx\nMyComponent.propTypes = {\n  arrayProp: PropTypes.arrayOf((propValue, key, componentName, location, propFullName) => {\n    if (!/matchme/.test(propValue[key])) {\n      // 它应该在验证失败时返回一个 Error 对象。\n      return new Error(\n        ''Invalid prop `'' + propFullName + ''` supplied to'' +\n        '' `'' + componentName + ''`. Validation failed.''\n      );\n    }\n  })\n}\n```\n\n`propValue` 是数组或对象本身，`key` 是他们当前的键。\n\n### 数组\n\n```jsx\nMyComponent.propTypes = {\n  arr: PropTypes.arrayOf(PropTypes.number),\n};\n```\n\n可以指定一个数组由某一类型的元素组成\n\n### 验证类的实例\n\n```jsx\nMyComponent.propTypes = {\n  message: PropTypes.instanceOf(Message),\n};\n```\n\n声明 `message` 为类的实例\n\n另见\n----\n\n- [React 官方中文文档](https://zh-hans.reactjs.org/) _(zh-hans.reactjs.org)_\n- [反应生命周期方法图](https://projects.wojtekmaj.pl/react-lifecycle-methods-diagram/) _(projects.wojtekmaj.pl)_\n- [React 16 Cheat Sheet](https://reactcheatsheet.com)\n- [Awesome React](https://github.com/enaqx/awesome-react) _(github.com)_','\n',char(10)),'React 备忘清单','','','PUBLIC','DRAFT',NULL,'2025-12-17 18:57:43.7471654+00:00',1,'2025-12-17 18:57:18.909058811+00:00','2025-12-17 18:57:43.755110682+00:00',NULL);
INSERT INTO blog_post VALUES(2,'React 备忘清单 backlist','react-bei-wang-qing-dan-backlist','',replace('React 备忘清单\n===\n\n[![NPM version](https://img.shields.io/npm/v/react.svg?style=flat)](https://npmjs.org/package/react)\n[![Downloads](https://img.shields.io/npm/dm/react.svg?style=flat)](https://www.npmjs.com/package/react)\n[![Repo Dependents](https://badgen.net/github/dependents-repo/facebook/react)](https://github.com/facebook/react/network/dependents)\n[![Github repo](https://badgen.net/badge/icon/Github?icon=github&label)](https://github.com/facebook/react)\n\n适合初学者的综合 React 备忘清单\n<!--rehype:style=padding-top: 12px;-->\n\n入门\n----\n\n### 介绍\n\nReact 是一个用于构建用户界面的 JavaScript 库\n\n- [React 官方文档](https://react.dev) _(react.dev)_\n- [Styled Components 备忘清单](./styled-components.md) _(jaywcjlove.github.io)_\n- [TypeScript JSX 备忘清单](./typescript.md#jsx) _(jaywcjlove.github.io)_\n\n```js\nimport {createRoot} from ''react-dom/client''\nimport App from ''./App''\n```\n\n-----\n\n```jsx\nconst elm = document.getElementById(''app'')\nconst root = createRoot(elm);\nroot.render(<App />);\n```\n\n#### 快速创建 **React** 项目 ([CRA](https://github.com/facebook/create-react-app))\n\n```shell\nnpx create-react-app my-app\n```\n\n### 导入多个导出\n\n```jsx\nimport React, {Component} from ''react''\nimport ReactDOM from ''react-dom''\n```\n\n-----\n\n```jsx\nexport class Hello extends Component {\n  ...\n}\nexport default function World() {\n  /* ... */\n}\n```\n\n使用 `export` 导出 **`Hello`**，`export default` 导出 **`World`** 组件\n\n```jsx\nimport World, { Hello } from ''./hello.js'';\n```\n\n使用 `import` 导入 `Hello` 组件，在示例中使用。\n\n### React 组件中的 CSS\n\n```jsx {2,5}\nimport React from "react";\nimport "./Student.css";\n\nexport const Student = (\n  <div className="Student"></div>\n);\n```\n\n注意：类属性 `className`\n\n```jsx\nconst divStyle = {\n  backgroundImage: ''url('' + imgUrl + '')'',\n};\nexport const Student = (\n  <div style={divStyle}></div>\n);\n```\n\n### 属性\n\n```jsx\n<Student name="Julie" age={23}\n  pro={true} />\n```\n\n函数组件 `Student` 中访问属性\n\n```jsx\nfunction Student(props) {\n  return <h1>Hello, {props.name}</h1>;\n}\n```\n\nClass 组件 `Student` 中访问属性\n\n```jsx\nclass Student extends React.Component {\n  render() {\n    return (\n      <h1>Hello, {this.props.name}</h1>\n    );\n  }\n}\n```\n\n`class` 组件使用 `this.props` 访问传递给组件的属性。\n\n### Children\n<!--rehype:wrap-class=row-span-2-->\n\n```jsx\nfunction Example() {\n  return (\n    <AlertBox>\n      <h1>您有待处理的通知</h1>\n    </AlertBox>\n  )\n}\n```\n\n函数 `AlertBox` 组件\n\n```jsx {4}\nfunction AlertBox(props) {\n  return (\n    <div className="alert-box">\n      {props.children}\n    </div>\n  );\n}\n```\n\n-----\n\n```jsx\n{props.children}\n```\n\nClass `AlertBox` 组件，与函数组件 `AlertBox` 组件相同\n\n```jsx {5}\nclass AlertBox extends React.Component {\n  render () {\n    return (\n      <div className="alert-box">\n        {this.props.children}\n      </div>\n    );\n  }\n}\n```\n\n-----\n\n```jsx\n{this.props.children}\n```\n\n`children` 作为子组件的的属性传递。\n\n### State\n<!--rehype:wrap-class=row-span-3-->\n\n函数中的 State，Hook 是 React 16.8 的新增特性\n\n```jsx {4,8}\nimport { useState } from ''react'';\n\nfunction Student() {\n  const [count, setCount] = useState(0);\n  const click = () => setCount(count + 1);\n  return (\n    <div>\n      <p>您点击了 {count} 次</p>\n      <button onClick={click}>\n        点击我\n      </button>\n    </div>\n  );\n}\n```\n\n使用 `setState` 更新状态，下面是函数组件读取状态\n\n```jsx\n<p>您点击了 {count} 次</p>\n```\n\n#### Class 中的 State\n\n```jsx {6,12,20}\nimport React from ''react'';\n\nclass Student extends React.Component {\n  constructor(props) {\n    super(props);\n    this.state = {count: 1};\n    // 确保函数可以访问组件属性（ES2015）\n    this.click = this.click.bind(this);\n  }\n  click() {\n    const count = this.state.count;\n    this.setState({ count: count + 1})\n  }\n  render() {\n    return (\n      <div>\n        <button onClick={this.click}>\n          点击我\n        </button>\n        <p>您点击了{this.state.count}次</p>\n      </div>\n    );\n  }\n}\n```\n\n使用 `setState` 更新状态，`class` 组件中不能使用 <yel>~~hooks~~</yel>。下面是 `class` 组件读取状态\n\n```jsx\n<p>您点击了{this.state.count}次</p>\n```\n\n### 循环\n\n```jsx\nconst elm = [''one'', ''two'', ''three''];\nfunction Student() {\n  return (\n    <ul>\n      {elm.map((value, index) => (\n        <li key={index}>{value}</li>\n      ))}\n    </ul>\n  );\n}\n```\n\n`key` 值在兄弟节点之间必须唯一\n\n### 事件监听\n\n```jsx\nexport default function Hello() {\n  function handleClick(event) {\n    event.preventDefault();\n    alert("Hello World");\n  }\n\n  return (\n    <a href="/" onClick={handleClick}>\n      Say Hi\n    </a>\n  );\n}\n```\n\n### 函数注入\n\n```jsx\nfunction addNumbers(x1, x2) {\n  return x1 + x2;\n}\n\nconst element = (\n  <div>\n    {addNumbers(2, 5)}\n  </div>\n);\n```\n\n### 嵌套\n\n```jsx\nimport { useState } from ''react''\nimport Avatar from ''./Avatar'';\nimport Profile from ''./Profile'';\n\nfunction Student() {\n  const [count, setCount] = useState(0);\n  return (\n    <div>\n      <Avatar src={count} />\n      <Profile username={count} />\n    </div>\n  );\n}\n```\n\n### Portals\n\nReact 并_没有_创建一个新的 `div`。它只是把子元素渲染到 `domNode` 中。`domNode` 是一个可以在任何位置的有效 DOM 节点。\n\n```jsx\nrender() {\n  return ReactDOM.createPortal(\n    this.props.children,\n    domNode\n  );\n}\n```\n\n提供了一种将子节点渲染到存在于父组件以外的 DOM 节点的优秀的方案\n\n### Fragment\n<!--rehype:wrap-class=row-span-2-->\n\n```jsx {1,6,9}\nimport { Fragment } from ''react''\nimport Avatar from ''./Avatar'';\nimport Profile from ''./Profile'';\n\nconst Student = () => (\n  <Fragment>\n    <Avatar src="./demo.jpg" />\n    <Profile username="name" />\n  </Fragment>\n);\n```\n\n从 `v16.2.0` 开始 `Fragment` 可用于返回多个子节点，而无需向 DOM 添加额外的包装节点。或者使用 `<></>` 效果是一样的。\n\n```jsx {2,5}\nconst Student = () => (\n  <>\n    <Avatar src="./demo.jpg" />\n    <Profile username="name" />\n  </>\n);\n```\n\n查看: [Fragments & strings](https://reactjs.org/blog/2017/09/26/react-v16.0.html#new-render-return-types-fragments-and-strings)\n\n### 返回字符串\n\n```jsx {2}\nrender() {\n  return ''Look ma, no spans!'';\n}\n```\n\n您可以只返回一个字符串。查看: [Fragments & strings](https://reactjs.org/blog/2017/09/26/react-v16.0.html#new-render-return-types-fragments-and-strings)\n\n### 返回数组\n\n```jsx\nconst Student = () => [\n  <li key="A">First item</li>,\n  <li key="B">Second item</li>\n];\n```\n\n不要忘记 `key`！查看: [Fragments & strings](https://reactjs.org/blog/2017/09/26/react-v16.0.html#new-render-return-types-fragments-and-strings)\n\n### Refs 转发\n\n```jsx\nconst FancyButton = React.forwardRef(\n  (props, ref) => (\n    <button ref={ref} className="btn">\n      {props.children}\n    </button>\n  )\n);\n```\n\n#### 使用\n\n```jsx\n// 你可以直接获取 DOM button 的 ref：\nconst ref = React.createRef();\n\n<FancyButton ref={ref}>\n  点击我\n</FancyButton>;\n```\n\n### Class 组件内部使用 ref 属性\n\n```jsx {6,10}\nimport {Component,createRef} from ''react''\n\nclass MyComponent extends Component {\n  constructor(props) {\n    super(props);\n    this.myRef = createRef();\n  }\n\n  render() {\n    return <div ref={this.myRef} />;\n  }\n}\n```\n\n提示：Refs 适用于类组件，但不适用于函数组件（除非您使用 useRef hook，请参阅[hooks](#hooks)）\n\n### 函数组件内部使用 ref 属性\n\n```jsx {3,9}\nfunction CustomTextInput(props) {\n  // 这里必须声明 $input，这样 ref 才可以引用它\n  const $input = useRef(null);\n  function handleClick() {\n    $input.current.focus();\n  }\n  return (\n    <div>\n      <input type="text" ref={$input} />\n      <input\n        type="button" value="聚焦文本输入"\n        onClick={handleClick}\n      />\n    </div>\n  );\n}\n```\n\n### 严格模式 StrictMode\n\n```jsx {3,8}\n<div>\n  <Header />\n  <React.StrictMode>\n    <div>\n      <ComponentOne />\n      <ComponentTwo />\n    </div>\n  </React.StrictMode>\n  <Footer />\n</div>\n```\n\n-----\n\n- [识别不安全的生命周期](https://zh-hans.reactjs.org/docs/strict-mode.html#identifying-unsafe-lifecycles)\n- [关于使用过时字符串 ref API 的警告](https://zh-hans.reactjs.org/docs/strict-mode.html#warning-about-legacy-string-ref-api-usage)\n- [关于使用废弃的 findDOMNode 方法的警告](https://zh-hans.reactjs.org/docs/strict-mode.html#warning-about-deprecated-finddomnode-usage)\n- [检测意外的副作用](https://zh-hans.reactjs.org/docs/strict-mode.html#detecting-unexpected-side-effects)\n- [检测过时的 context API](https://zh-hans.reactjs.org/docs/strict-mode.html#detecting-legacy-context-api)\n- [确保可复用的状态](https://zh-hans.reactjs.org/docs/strict-mode.html#ensuring-reusable-state)\n\n突出显示应用程序中潜在问题的工具。请参阅：[严格模式](https://zh-hans.reactjs.org/docs/strict-mode.html)\n\n### Profiler\n<!--rehype:wrap-class=col-span-2-->\n\n测量一个 React 应用多久渲染一次以及渲染一次的 `代价`\n\n```jsx\n<Profiler id="Navigation" onRender={callback}>\n  <Navigation {...props} />\n</Profiler>\n```\n\n为了分析 `Navigation` 组件和它的子代。应该在需要时才去使用它。\n\n:- | :-\n:- | :-\n`id(string)` | 发生提交的 `Profiler` 树的 `id`\n`onRender(function)` | 组件树任何组件 “提交” 一个更新的时候调用这个函数\n\n#### onRender 回调函数\n\n:- | :-\n:- | :-\n`phase: "mount" \| "update"` |  判断是由 `props`/`state`/`hooks` 改变 或 “第一次装载” 引起的重渲染\n`actualDuration: number` | 本次更新在渲染 Profiler 和它的子代上花费的时间\n`baseDuration: number` | 在 Profiler 树中最近一次每一个组件 render 的持续时间\n`startTime: number` | 本次更新中 React 开始渲染的时间戳\n`commitTime: number` | 本次更新中 React commit 阶段结束的时间戳\n`interactions: Set` | 当更新被制定时，“[interactions](https://fb.me/react-interaction-tracing)” 的集合会被追踪\n\n默认值\n---\n\n### Class 组件默认 props\n<!--rehype:wrap-class=row-span-2-->\n\n```jsx\nclass CustomButton extends React.Component {\n  // ...\n}\nCustomButton.defaultProps = {\n  color: ''blue''\n};\n```\n\n#### 使用\n\n```jsx\n<CustomButton /> ;\n```\n\n不传值 `props.color` 将自动设置为 `blue`\n\n### Class 组件默认 state\n<!--rehype:wrap-class=row-span-2-->\n\n```jsx\nclass Hello extends Component {\n  constructor (props) {\n    super(props)\n    this.state = { visible: true }\n  }\n}\n```\n\n在构造 `constructor()`中设置默认状态。\n\n```jsx\nclass Hello extends Component {\n  state = { visible: true }\n}\n```\n\n### 函数组件默认 props\n\n```jsx\nfunction CustomButton(props) {\n  const { color = ''blue'' } = props;\n  return <div>{color}</div>\n}\n```\n\n### 函数组件默认 state\n\n```jsx\nfunction CustomButton() {\n  const [color, setColor]=useState(''blue'')\n  return <div>{color}</div>\n}\n```\n\nProps\n---\n\n### Props 的 Spread 运算符\n\n扩展运算符可用于一次传递所有 Props。\n\n```jsx\nfunction Profile(props) {\n  return <p>{props.name}, {props.age}</p>;\n}\n\nconst user = { name: "John", age: 25 };\n<Profile {...user}/>\n```\n\n### 什么是 Props？\n\n- Props（“properties”的缩写）用于将数据从父组件传递到子组件。\n- 它们是只读的，不能在子组件内修改。\n\n```jsx\n<MyComponent propName="value" />\n```\n\n### 将 Pros 传递给组件\n\n您可以通过 JSX 中的属性将 props 从父组件传递到子组件。\n\n```jsx\nfunction ParentComponent() {\n  return <ChildComponent name="John" age={25} />;\n}\n\nfunction ChildComponent (props) {\n  return <div>Hello，{props.name}. You are {props.age} years old. </div>;\n}\n```\n\n### 解构 props\n\nprops 可以解构以便于访问。\n\n```jsx\nfunction Greeting({ name }) {\n  return <h1>Hello, {name}!</h1>;\n}\n```\n\n### 访问功能组件中的 Props\n\n可以使用 props 对象在功能组件中访问 Props。\n\n```jsx\nfunction Greeting(props) {\n  return <h1>Hello, {props.name}!</h1>;\n}\n```\n\n### 使用 Pros 进行条件渲染\n\n道具可用于组件内部的条件渲染。\n\n```jsx\nfunction Greeting({ name, isLoggedIn }) {\n  return isLoggedIn ? <hl>Welcome back, {name}</h1>: <h1>Please log in</h1>;\n}\n```\n\n### Prop Drilling（属性传递）\n<!--rehype:wrap-class=row-span-2-->\n\n```js\nfunction Parent() {\n  const name = "John";\n  return <Child name={name}/>;\n}\n\nfunction Child({ name }) {\n  return <Grandchild name={name} />\n}\n\nfunction Grandchild({ name }) {\n  return <p>{name}</p>;\n}\n```\n\n将属性（props）在多个组件层级中逐层传递可能会变得繁琐。这种方式称为属性传递（prop drilling）。\n\n### Props 与 State\n<!--rehype:wrap-class=row-span-2-->\n\n- `props` 被传递给组件并且是不可变的。\n- `State` 是组件的本地状态，可以更改。\n\n```jsx\nfunction ChildComponent({ name }) {\n  return <h2>Hi,my name is {name}.</h2>;\n}\n\nfunction ParentComponent() {\n  // State to manage the name value\n  const ［name, setName］= usestate(''John'');\n  const changeName = () => {\n    setName(''Jane'');\n  };\n  return (\n    <div>\n      <ChildComponent name={name}/>\n      <button onClick={changeName}>\n        Change Names\n      </button>\n    </div>\n  );\n}\n```\n\n### 默认 props\n\n```jsx\nfunction Greeting({ name = "Bob" } = 0}) {\n  return <h1>Hello, {name}!</h1>;\n}\n// Renders "Hello, Bob!"\n< Greeting />\n```\n\n您可以为 `props` 设置默认值。\n\n### 使用 prop 处理事件\n\n你可以将事件处理程序作为 props 传递给 handle 用户交互。\n\n```jsx\nfunction Button({ onClick }) {\n  return < button onClick={onClick}>Click me</button>;\n}\n\nfunction App() {\n  const handleClick = () => alert("Button clicked!"):\n  return <Button onClick={handleClick} />;\n}\n```\n\nJSX\n---\n\n### 介绍\n<!--rehype:wrap-class=row-span-2-->\n\n`JSX` 仅仅只是 `React.createElement(component, props, ...children)` 函数的语法糖\n\n```jsx\n<MyButton color="blue" shadowSize={2}>\n  点击我\n</MyButton>\n```\n\n会编译为\n\n```js\nReact.createElement(\n  MyButton,\n  {color: ''blue'', shadowSize: 2},\n  ''点击我''\n);\n```\n\n没有子节点\n\n```jsx\n<div className="sidebar" />\n```\n\n会编译为\n\n```js\nReact.createElement(\n  ''div'',\n  {className: ''sidebar''}\n)\n```\n\n### JSX 点语法\n\n```jsx\nconst Menu = ({ children }) => (\n  <div className="menu">{children}<div>\n);\n\nMenu.Item = ({ children }) => (\n  <div>{children}<div>\n);\n\n<Menu>\n  <Menu.Item>菜单一</Menu.Item>\n  <Menu.Item>菜单二</Menu.Item>\n<Menu>\n```\n\n### JSX Element\n\n```jsx\nlet element = <h1>Hello, world!</h1>;\nlet emptyHeading = <h1 />;\n\nconst root = ReactDOM.createRoot(\n  document.getElementById(''root'')\n);\n\nconst element = <h1>Hello, world</h1>;\nroot.render(element);\n```\n\n参考：[渲染元素](https://reactjs.org/docs/rendering-elements.html)\n\n### JSX 属性\n\n```jsx\nconst avatarUrl = "img/picture.jpg"\nconst element = <img src={avatarUrl} />;\n\nconst element = (\n  <button className="btn">\n    点击我\n  </button>\n);\n```\n\n注意：类属性 `className`\n\n### JSX 表达式\n\n```jsx\nlet name = ''张三'';\nlet element = <h1>Hello, {name}</h1>;\n\nfunction fullName(firstName, lastName) {\n  return firstName + '' '' + lastName;\n}\nlet element = (\n  <h1>\n    Hello, {fullName(''三'', ''张'')}\n  </h1>\n);\n```\n\n### JSX style\n\n```jsx\nconst divStyle = {\n  color: ''blue'',\n  backgroundImage: ''url('' + imgUrl + '')'',\n};\nfunction MyComponent() {\n  return <div style={divStyle}>组件</div>;\n}\n```\n\n### JSX dangerouslySetInnerHTML\n\n```jsx\nconst markup = {__html: ''我 &middot; 你'' };\n\nconst MyComponent = () => (\n  <div dangerouslySetInnerHTML={markup} />\n);\n```\n\n`dangerouslySetInnerHTML` 是 React 为浏览器 DOM 提供 `innerHTML` 的替换方案。\n\n### JSX htmlFor\n\n```jsx\nconst MyComponent = () => (\n  <div>\n    <input type="radio" id="ab" name="v">\n    <label for="ab">HTML</label>\n  </div>\n);\n```\n\n`for` 在 `JS` 中是保留字，JSX 元素使用了 `htmlFor` 代替\n\n### JSX defaultValue\n\n非受控组件的属性，设置组件第一次挂载时的 `value`\n\n```jsx\n<textarea defaultValue="Hello" />\n```\n\n`<input>`、`<select>` 和 `<textarea>` 支持 value 属性\n\n### JSX defaultChecked\n\n非受控组件的属性，设置组件是否被选中\n\n```jsx\n<input type="radio" defaultChecked />\n```\n\n类型为 `checkbox` 或 `radio` 时，组件支持 checked 属性\n\n### JSX className\n\n属性用于指定 `CSS` 的 `class`\n\n```jsx\n<div className="warp">...</div>\n```\n\nReact 中使用 [Web Components](https://developer.mozilla.org/zh-CN/docs/Web/Web_Components) 使用 `class` 属性代替\n\n### JSX 条件渲染\n<!--rehype:wrap-class=row-span-2-->\n\n```jsx\nimport React from "react";\n\nfunction formatName(user) {\n  return user.firstName \n    + '' '' \n    + user.lastName;\n}\n\nexport function Greeting(user) {\n  if (user) {\n    return (\n      <h1>你好, {formatName(user)}!</h1>\n    );\n  }\n  return (\n    <h1>你好, 先生。</h1>\n  );\n}\n```\n\n注意：组件必须总是返回一些东西。\n\n#### 使用\n\n```jsx\n<Greeting firstName="三" lastName="张" />\n```\n\n### JSX 三目运算符 / 与运算符 &&\n\n```jsx\nexport default function Weather(props) {\n  const isLoggedIn = props.isLoggedIn;\n  return (\n    <div>\n      <b>{isLoggedIn ? ''已'' : ''未''}</b>登录。\n    </div>\n  );\n}\n```\n\n-----\n\n```js\n{isShow && <div>内容</div>}\n```\n\n### JSX 组件\n\n```jsx\n<Dropdown>\n  下拉列表\n  <Menu>\n    <Menu.Item>菜单一</Menu.Item>\n    <Menu.Item>菜单二</Menu.Item>\n    <Menu.Item>菜单三</Menu.Item>\n  </Menu>\n</Dropdown>\n```\n\n组件名称以大驼峰式命名。\n\n### JSX 元素变量\n\n```jsx\nfunction Greeting(props) {\n  let button;\n  if (props.isLoggedIn) {\n    button = <UserGreeting />;\n  } else {\n    button = <GuestGreeting />;\n  }\n  return <div>{button}</div>;\n}\n```\n\n### JSX 注释\n\n```jsx\nfunction Student() {\n  const [count, setCount] = useState(0);\n  return (\n    <Fragment>\n      {/* 这里写注释 */}\n    </Fragment>\n  );\n}\n```\n\n组件\n----\n\n### 函数组件\n<!--rehype:wrap-class=row-span-2-->\n\n```jsx\nimport React from ''react'';\n\nconst UserName = () => <h1>Kenny</h1>;\n\nexport default function UserProfile() {\n  return (\n    <div className="UserProfile">\n      <div>Hello</div>  \n      <UserName />\n    </div>\n  );\n}\n```\n\n注意：每个组件都需要一个根元素，[更多说明](https://reactjs.org/docs/components-and-props.html)。\n\n### Class 组件\n\n```jsx\nclass Welcome extends React.Component {\n  render() {\n    return <h1>{this.props.name}</h1>;\n  }\n}\n```\n\n### Class 组件 API\n<!--rehype:wrap-class=row-span-2-->\n\n#### 额外的 API\n\n:- | -\n:- | -\n`this.forceUpdate()` | 强制重新渲染\n`this.setState({ ... })` | 更新状态\n`this.setState(state =>{ ... })` | 更新状态\n\n#### 属性\n\n:- | -\n:- | -\n`defaultProps` | 默认 props\n`displayName` | 显示组件名称(用于调试)\n\n#### 实例属性\n\n:- | -\n:- | -\n`this.props` | 组件接受参数\n`this.state` | 组件内状态\n\n### Pure 组件\n\n```jsx\nimport React, {PureComponent} from ''react''\n\nclass MessageBox extends PureComponent {\n  ···\n}\n```\n\n### 高阶组件\n\n```jsx\nimport React, { Component } from ''react'';\n// 高阶组件 with\nconst with = data => WrappedComponent => {\n  return class extends Component {\n    constructor(props) {\n      super(props);\n    }\n    render() {\n      return (\n        <WrappedComponent data={data} />\n      )\n    }\n  }\n}\n```\n\n使用高阶组件\n\n```jsx\nconst LowComponent = (props) => (\n  <div>{props.data}</div>\n);\n\nconst MyComp = with(''Hello'')(LowComponent)\n```\n\n### 包含关系\n\n```jsx\nfunction FancyBorder(props) {\n  return (\n    <div className={''Fancy''+props.color}>\n      {props.children}\n    </div>\n  );\n}\n```\n\n组件可以通过 JSX 嵌套\n\n```jsx\nfunction WelcomeDialog() {\n  return (\n    <FancyBorder color="blue">\n      <h1 className="title">欢迎</h1>\n      <p className="message">\n        感谢您访问我们的宇宙飞船\n      </p>\n    </FancyBorder>\n  );\n}\n```\n\n### 作为参数传递\n\n```jsx\nfunction SplitPane(props) {\n  return (\n    <div className="SplitPane">\n      <div className="left">\n        {props.left}\n      </div>\n      <div className="right">\n        {props.right}\n      </div>\n    </div>\n  );\n}\n\nfunction App() {\n  return (\n    <SplitPane\n      left={<Contacts />}\n      right={<Chat />}\n    />\n  );\n}\n```\n\n给组件 `SplitPane` 传递 `left` 和 `right` 两个组件参数\n\n### 嵌入内部组件\n\n```jsx {2}\nimport React from ''react'';\nimport UserAvatar from "./UserAvatar";\n\nexport default function UserProfile() {\n  return (\n    <div className="UserProfile">\n      <UserAvatar />\n      <UserAvatar />\n    </div>\n  );\n}\n```\n\n注意：假设 `UserAvatar` 在 `UserAvatar.js` 中声明\n\n### 嵌入外部组件\n\n```jsx {2}\nimport React from ''react'';\nimport {Button} from ''uiw'';\nexport default function UserProfile() {\n  return (\n    <div className="UserProfile">\n      <Button type="primary">\n        主要按钮\n      </Button>\n    </div>\n  );\n}\n```\n\n注意：[uiw](http://npmjs.com/uiw) 组件在 [npmjs.com](https://www.npmjs.com) 上找到，需要先安装导入\n\n### 点组件语法技巧\n\n```jsx\nconst Menu = ({ children }) => (\n  <div className="menu">{children}<div>\n);\n\nMenu.Item = ({ children }) => (\n  <div>{children}<div>\n);\n```\n\n-----\n\n```jsx\n<Menu>\n  <Menu.Item>菜单一</Menu.Item>\n  <Menu.Item>菜单二</Menu.Item>\n<Menu>\n```\n\nHooks\n---\n\n### Hooks API 参考\n<!--rehype:wrap-class=row-span-2-->\n\n#### 基础 Hook\n\n方法 | 描述\n:- | -\n`useState` | 返回一个 `state`，更新 `state` 的函数 [#](https://zh-hans.reactjs.org/docs/hooks-reference.html#usestate)\n`useEffect` | 可能有副作用代码的函数 [#](https://zh-hans.reactjs.org/docs/hooks-reference.html#useeffect)\n`useContext` | 接收并返回该 `context` 的当前值 [#](https://zh-hans.reactjs.org/docs/hooks-reference.html#usecontext)\n\n#### 额外的 Hook\n\n方法 | 描述\n:- | -\n`useReducer` | `useState` 的替代方案 [#](https://zh-hans.reactjs.org/docs/hooks-reference.html#usestate)\n`useCallback` | 返回一个回调函数 [#](https://zh-hans.reactjs.org/docs/hooks-reference.html#usecallback)\n`useMemo` | 返回一个 [memoized](https://en.wikipedia.org/wiki/Memoization) 值[#](https://zh-hans.reactjs.org/docs/hooks-reference.html#usememo)\n`useRef` | 返回一个可变的 `ref` 对象 [#](https://zh-hans.reactjs.org/docs/hooks-reference.html#useref)\n`useImperativeHandle` | 暴露给父组件的实例值 [#](https://zh-hans.reactjs.org/docs/hooks-reference.html#useimperativehandle)\n`useLayoutEffect` | DOM 变更后同步调用函数 [#](https://zh-hans.reactjs.org/docs/hooks-reference.html#uselayouteffect)\n`useDebugValue` | 开发者工具中显示标签 [#](https://zh-hans.reactjs.org/docs/hooks-reference.html#usedebugvalue)\n`useDeferredValue` | 接受并返回该值的新副本 [#](https://zh-hans.reactjs.org/docs/hooks-reference.html#usedeferredvalue)\n`useTransition` | 过渡任务的等待状态 [#](https://zh-hans.reactjs.org/docs/hooks-reference.html#usetransition)\n`useId` | 用于生成唯一 ID [#](https://zh-hans.reactjs.org/docs/hooks-reference.html#useid)\n\n#### Library Hooks\n\n方法 | 描述\n:- | -\n`useSyncExternalStore` | 读取和订阅外部数据源 [#](https://zh-hans.reactjs.org/docs/hooks-reference.html#usesyncexternalstore)\n`useInsertionEffect` |  DOM 突变之前 同步触发 [#](https://zh-hans.reactjs.org/docs/hooks-reference.html#usesyncexternalstore)\n\n### 函数式更新\n<!--rehype:wrap-class=col-span-2-->\n\n```jsx\nfunction Counter({ initialCount }) {\n  const [count, setCount] = useState(initialCount);\n  return (\n    <>\n      Count: {count} <button onClick={() => setCount(initialCount)}>Reset</button>\n      <button onClick={() => setCount(prevCount => prevCount - 1)}>-</button>\n      <button onClick={() => setCount(prevCount => prevCount + 1)}>+</button>\n    </>\n  );\n}\n```\n\n### useRef\n\n```jsx\nfunction TextInputWithFocusButton() {\n  const $input = useRef(null);\n  const onButtonClick = () => {\n    $input.current.focus();\n  };\n  return (\n    <>\n      <input ref={$input} type="text" />\n      <button onClick={onButtonClick}>\n        聚焦输入\n      </button>\n    </>\n  );\n}\n```\n\n`current` 指向已挂载到 DOM 上的文本输入元素\n\n### useImperativeHandle\n\n```jsx\nfunction FancyInput(props, ref) {\n  const inputRef = useRef();\n  useImperativeHandle(ref, () => ({\n    focus: () => {\n      inputRef.current.focus();\n    }\n  }));\n  return <input ref={inputRef} />;\n}\nFancyInput = forwardRef(FancyInput);\n```\n\n父组件使用\n\n```jsx\n<FancyInput ref={inputRef} />\ninputRef.current.focus()\n```\n\n### useEffect\n\n```jsx\nuseEffect(() => {\n  const subs = props.source.subscribe();\n  return () => {\n    subs.unsubscribe();\n  };\n}, [props.source]);\n```\n\n### useCallback\n\n```jsx\nconst memoizedCallback = useCallback(\n  () => {\n    doSomething(a, b);\n  },\n  [a, b],\n);\n```\n\n### useMemo\n\n```jsx\nconst memoizedValue = useMemo(\n  () => {\n    return computeExpensiveValue(a, b)\n  },\n  [a, b]\n);\n```\n\n### useId\n\n```jsx\nfunction Checkbox() {\n  const id = useId();\n  return (\n    <>\n      <label htmlFor={id}>\n        你喜欢React吗？\n      </label>\n      <input id={id} type="checkbox" />\n    </>\n  );\n};\n```\n\n用于生成跨服务端和客户端稳定的唯一 `ID` 的同时避免 `hydration` 不匹配\n\n### useDebugValue\n\n```jsx\nfunction useFriendStatus(friendID) {\n  const [\n    isOnline, setIsOnline\n  ] = useState(null);\n  // ...\n  // 在开发者工具中的这个 Hook 旁边显示标签\n  // e.g. "FriendStatus: Online"\n  useDebugValue(\n    isOnline ? ''Online'' : ''Offline''\n  );\n  return isOnline;\n}\n```\n<!--rehype:className=wrap-text -->\n\n不推荐你向每个自定义 `Hook` 添加 `debug` 值\n\n### componentDidMount & componentWillUnmount\n\n```jsx\nuseEffect(\n  () => {\n    // componentDidMount\n    // 组件挂载时，可以在这里完成你的任务\n    return () => {\n      // componentWillUnmount\n      // 卸载时执行，清除 effect\n    };\n  },\n  [ ]\n);\n```\n\n这是一个类似 `class` 组件中 `componentDidMount` & `componentWillUnmount` 两个生命周期函数的写法。\n\n生命周期\n---\n<!--rehype:body-class=cols-2-->\n\n### 挂载\n<!--rehype:wrap-class=row-span-2-->\n\n方法 | 描述\n:- | -\n`constructor` _(props)_  | 渲染前 [#](https://zh-hans.reactjs.org/docs/react-component.html#constructor)\n`static getDerivedStateFromProps()` | 调用 `render` 方法之前调用 [#](https://zh-hans.reactjs.org/docs/react-component.html#static-getderivedstatefromprops)\n`render()`               |  `class` 组件中唯一必须实现的方法 [#](https://reactjs.org/docs/react-component.html#render)\n`componentDidMount()`    | 在组件挂载后(插入 DOM 树中)立即调用 [#](https://reactjs.org/docs/react-component.html#componentdidmount)\n`UNSAFE_componentWillMount()` | 在挂载之前被调用，建议使用 `constructor()` [#](https://zh-hans.reactjs.org/docs/react-component.html#unsafe_componentwillmount)\n\n在 `constructor()` 上设置初始状态。在 `componentDidMount()` 上添加 DOM 事件处理程序、计时器(等），然后在 `componentWillUnmount()` 上删除它们。\n\n### 卸载\n\n方法 | 描述\n:- | -\n`componentWillUnmount()` | 在组件卸载及销毁之前直接调用 [#](https://zh-hans.reactjs.org/docs/react-component.html#componentwillunmount)\n\n### 过时 API\n\n过时方法 | 新方法\n:- | -\n~~`componentWillMount()`~~ | `UNSAFE_componentWillMount()`  [#](https://zh-hans.reactjs.org/docs/react-component.html#unsafe_componentwillmount)\n~~`componentWillReceiveProps()`~~ | `UNSAFE_componentWillReceiveProps()`  [#](https://zh-hans.reactjs.org/docs/react-component.html#unsafe_componentwillreceiveprops)\n~~`componentWillUpdate()`~~ | `UNSAFE_componentWillUpdate()`  [#](https://zh-hans.reactjs.org/docs/react-component.html#unsafe_componentwillupdate)\n\n17+ 之后不再支持，在 `17` 版本之后，只有新的 `UNSAFE_` 生命周期名称可以使用。\n\n### 更新\n<!--rehype:wrap-class=col-span-2-->\n\n方法 | 描述\n:- | -\n`static getDerivedStateFromProps(props, state)` | 调用 `render` 之前调用，在初始挂载及后续更新时都会被调用 [#](https://zh-hans.reactjs.org/docs/react-component.html#static-getderivedstatefromprops)\n`shouldComponentUpdate(nextProps, nextState)` | 如果返回 `false`，则跳过 `render()` [#](https://zh-hans.reactjs.org/docs/react-component.html#static-getderivedstatefromprops)\n`render()` | 在不修改组件 `state` 的情况下，每次调用时都返回相同的结果 [#](https://zh-hans.reactjs.org/docs/react-component.html#render)\n`getSnapshotBeforeUpdate()` | 在发生更改之前从 DOM 中捕获一些信息（例如，滚动位置） [#](https://zh-hans.reactjs.org/docs/react-component.html#getsnapshotbeforeupdate)\n`componentDidUpdate()` | 这里使用 `setState()`，但记得比较 `props`。首次渲染不会执行此方法 [#](https://zh-hans.reactjs.org/docs/react-component.html#componentdidupdate)\n\n### 错误处理\n<!--rehype:wrap-class=col-span-2-->\n\n方法 | 描述\n:- | -\n`static getDerivedStateFromError(error)` | 后代组件抛出错误后被调用，它将抛出的错误作为参数，并返回一个值以更新 `state` [#](https://zh-hans.reactjs.org/docs/react-component.html#static-getderivedstatefromerror)\n`componentDidCatch(error, info)` | 在后代组件抛出错误后被调用，会在“提交”阶段被调用，因此允许执行副作用 [#](https://zh-hans.reactjs.org/docs/react-component.html#componentdidcatch)\n\n### render()\n\n```jsx {2}\nclass Welcome extends React.Component {\n  render() {\n    return <h1>Hello, {this.props.name}</h1>;\n  }\n}\n```\n\n### constructor()\n\n```jsx {1}\nconstructor(props) {\n  super(props);\n  // 不要在这里调用 this.setState()\n  this.state = { counter: 0 };\n  this.handleClick = this.handleClick.bind(this);\n}\n```\n\n### static getDerivedStateFromError()\n<!--rehype:wrap-class=row-span-2-->\n\n```jsx {7,13}\nclass ErrorBoundary extends React.Component {\n  constructor(props) {\n    super(props);\n    this.state = { hasError: false };\n  }\n\n  static getDerivedStateFromError(error) {\n    // 更新 state 使下一次渲染可以显降级 UI\n    return { hasError: true };\n  }\n\n  render() {\n    if (this.state.hasError) {\n      // 你可以渲染任何自定义的降级  UI\n      return <h1>Something went wrong.</h1>;\n    }\n\n    return this.props.children;\n  }\n}\n```\n\n### componentDidUpdate()\n\n```jsx {1}\ncomponentDidUpdate(prevProps) {\n  // 典型用法（不要忘记比较 props）：\n  if (this.props.uid !== prevProps.uid) {\n    this.fetchData(this.props.uid);\n  }\n}\n```\n\n### getSnapshotBeforeUpdate()\n\n```jsx\ngetSnapshotBeforeUpdate(prevProps, prevState) {\n  // 我们是否在 list 中添加新的 items ？\n  // 捕获滚动​​位置以便我们稍后调整滚动位置。\n  if (prevProps.list.length < this.props.list.length) {\n    const list = this.listRef.current;\n    return list.scrollHeight - list.scrollTop;\n  }\n  return null;\n}\n```\n\nPropTypes 属性类型检查\n---\n\n### PropTypes\n<!--rehype:wrap-class=row-span-3-->\n\n```jsx\nimport PropTypes from ''prop-types''\n```\n\n-----\n\n:- | -\n:- | -\n`any` | 任意类型\n`(props, propName, 组件名称)=>{}` | 自定义验证器\n\n#### _基础_\n\n:- | -\n:- | -\n`string` | 字符串\n`number` | 数组\n`func` | 函数\n`bool` | 布尔值\n`symbol` | -\n\n#### _枚举 Enum_\n\n:- | -\n:- | -\n`oneOf(any)` | 枚举类型\n`oneOfType([type])` | 几种类型中的任意一个类型\n\n#### _数组 Array_\n\n:- | -\n:- | -\n`array` | 数组\n`arrayOf` | 数组由某一类型的元素组成\n\n#### _对象 Object_\n\n:- | -\n:- | -\n`object` | 对象\n`objectOf` | 对象由某一类型的值组成\n`instanceOf(...)` | 类的实例\n`shape` | 对象由特定的类型值组成\n`exact` | 有额外属性警告\n\n#### _元素 Elements_\n\n:- | -\n:- | -\n`element` | React 元素\n`elementType` | React 元素类型(即 `MyComponent`)\n`node` | DOM 节点\n\n#### _必需的_\n\n:- | -\n:- | -\n`(···).isRequired` | 必需的\n\n请参阅：[使用 PropTypes 进行类型检查](https://zh-hans.reactjs.org/docs/typechecking-with-proptypes.html)\n\n### 基本类型\n\n```jsx\nMyComponent.propTypes = {\n  email:      PropTypes.string,\n  seats:      PropTypes.number,\n  callback:   PropTypes.func,\n  isClosed:   PropTypes.bool,\n  any:        PropTypes.any\n  symbol:     PropTypes.symbol,\n}\n```\n\n你可以将属性声明为 JS 原生类型，默认都是可选的。\n\n### 必需的\n\n```jsx\nMyComponent.propTypes = {\n  // 确保这个 prop 没有被提供时，会打印警告信息\n  requiredFunc: PropTypes.func.isRequired,\n\n  // 任意类型的必需数据\n  requiredAny: PropTypes.any.isRequired,\n}\n```\n\n你可以在任何 `PropTypes` 属性后面加上 `isRequired`。\n\n### 枚举\n\n```js\nMyComponent.propTypes = {\n  // 只能是特定的值，枚举类型。\n  optionalEnum: PropTypes.oneOf([\n    ''News'', ''Photos''\n  ]),\n  // 一个对象可以是几种类型中的任意一个类型\n  optionalUnion: PropTypes.oneOfType([\n    PropTypes.string,\n    PropTypes.number,\n    PropTypes.instanceOf(Message)\n  ]),\n}\n```\n\n### 元素 Elements\n\n```jsx\nMyComponent.propTypes = {\n  // 任何可被渲染的元素\n  // (包括数字、字符串、元素或数组)\n  // (或 Fragment) 也包含这些类型。\n  node: PropTypes.node,\n\n  // 一个 React 元素。\n  element: PropTypes.element,\n\n  // 一个 React 元素类型（即，MyComponent）\n  elementType: PropTypes.elementType,\n}\n```\n\n### 对象 Object\n\n```jsx\nMyComponent.propTypes = {\n  // 可以指定一个对象由某一类型的值组成\n  objectOf: PropTypes.objectOf(\n    PropTypes.number\n  ),\n  // 可以指定一个对象由特定的类型值组成\n  objectWithShape: PropTypes.shape({\n    color: PropTypes.string,\n    fontSize: PropTypes.number\n  }),\n  // 带有额外属性警告的对象\n  objectWithStrictShape: PropTypes.exact({\n    name: PropTypes.string,\n    quantity: PropTypes.number\n  }),\n}\n```\n\n### 自定义验证器\n\n```jsx\nMyComponent.propTypes = {\n  custom: (props, propName, compName) => {\n    if (!/matchm/.test(props[propName])) {\n      // 它在验证失败时应返回一个 Error 对象\n      return new Error(\n        ''无效的prop `''\n        ` \`${propName}\` 提供给` + \n        ` \`${compName}\`。验证失败。`\n      );\n\n    }\n  },\n}\n```\n\n请不要使用 `console.warn` 或抛出异常，因为这在 `oneOfType` 中不会起作用。\n\n### 自定义的 `arrayOf` 或 `objectOf` 验证器\n<!--rehype:wrap-class=col-span-2 row-span-2-->\n\n```jsx\nMyComponent.propTypes = {\n  arrayProp: PropTypes.arrayOf((propValue, key, componentName, location, propFullName) => {\n    if (!/matchme/.test(propValue[key])) {\n      // 它应该在验证失败时返回一个 Error 对象。\n      return new Error(\n        ''Invalid prop `'' + propFullName + ''` supplied to'' +\n        '' `'' + componentName + ''`. Validation failed.''\n      );\n    }\n  })\n}\n```\n\n`propValue` 是数组或对象本身，`key` 是他们当前的键。\n\n### 数组\n\n```jsx\nMyComponent.propTypes = {\n  arr: PropTypes.arrayOf(PropTypes.number),\n};\n```\n\n可以指定一个数组由某一类型的元素组成\n\n### 验证类的实例\n\n```jsx\nMyComponent.propTypes = {\n  message: PropTypes.instanceOf(Message),\n};\n```\n\n声明 `message` 为类的实例\n\n另见\n----\n\n- [React 官方中文文档](https://zh-hans.reactjs.org/) _(zh-hans.reactjs.org)_\n- [反应生命周期方法图](https://projects.wojtekmaj.pl/react-lifecycle-methods-diagram/) _(projects.wojtekmaj.pl)_\n- [React 16 Cheat Sheet](https://reactcheatsheet.com)\n- [Awesome React](https://github.com/enaqx/awesome-react) _(github.com)_','\n',char(10)),'React 备忘清单','','','PUBLIC','DRAFT',NULL,NULL,1,'2025-12-17 18:59:18.784618547+00:00','2025-12-17 18:59:18.784618547+00:00',NULL);
COMMIT;
